/**
 * Execution context for running workflows.
 * This replaces the Commander.js Command object, making the code
 * usable both from CLI and as a scripting API.
 */
export interface ExecutionContext extends CliOptions {
  // All CLI options are inherited from CliOptions
}

type RunWorkflowOptions = {
  commandName: string
  context: ExecutionContext
  logger: Logger
  interactive?: boolean
  getProvider?: (args: ProviderOptions) => ToolProvider
  onUsageMeterCreated?: (meter: UsageMeter) => void
  onEvent?: WorkflowProgressCallback
  /** Optional provider/model override for this workflow execution */
  providerOverride?: {
    provider?: string
    model?: string
    parameters?: Record<string, unknown>
  }
  errorResult?: 'structured' | 'exitReason'
}

export type WorkflowFailureType =
  | 'user_cancelled'
  | 'configuration'
  | 'quota'
  | 'authentication'
  | 'model_access'
  | 'provider'
  | 'usage'
  | 'mcp'
  | 'tool'
  | 'workflow'

export type StructuredWorkflowFailure = {
  success: false
  reason: string
  summaries: []
  errorType: WorkflowFailureType
}

function errorMessage(error: unknown): string {
  return error instanceof Error ? error.message : 'Unknown error'
}

function errorStack(error: unknown): string | undefined {
  return error instanceof Error ? error.stack : undefined
}

export function toStructuredWorkflowFailure(error: unknown): StructuredWorkflowFailure {
  if (error instanceof UserCancelledError) {
    return { success: false, reason: error.message, summaries: [], errorType: 'user_cancelled' }
  }
  if (error instanceof ConfigurationError) {
    return { success: false, reason: error.message, summaries: [], errorType: 'configuration' }
  }
  if (error instanceof QuotaExceededError) {
    return { success: false, reason: error.message, summaries: [], errorType: 'quota' }
  }
  if (error instanceof MessageLimitExceededError) {
    return { success: false, reason: error.message, summaries: [], errorType: 'usage' }
  }
  if (error instanceof AuthenticationError) {
    return { success: false, reason: error.message, summaries: [], errorType: 'authentication' }
  }
  if (error instanceof ModelAccessError) {
    return { success: false, reason: error.message, summaries: [], errorType: 'model_access' }
  }
  if (error instanceof ProviderError) {
    return { success: false, reason: error.message, summaries: [], errorType: 'provider' }
  }
  if (error instanceof McpError) {
    return { success: false, reason: error.message, summaries: [], errorType: 'mcp' }
  }
  if (error instanceof ToolExecutionError) {
    return { success: false, reason: error.message, summaries: [], errorType: 'tool' }
  }
  return { success: false, reason: errorMessage(error), summaries: [], errorType: 'workflow' }
}

function toTerminalExitReason(error: unknown): ExitReason {
  if (error instanceof UserCancelledError) {
    return {
      type: 'Exit',
      message: error.message,
      messages: [],
    }
  }
  return {
    type: 'Error',
    error: {
      message: errorMessage(error),
      stack: errorStack(error),
    },
    messages: [],
  }
}

function isExitReason(output: unknown): output is ExitReason {
  return (
    output !== null &&
    typeof output === 'object' &&
    'type' in output &&
    (output.type === 'Exit' || output.type === 'Error' || output.type === 'UsageExceeded')
  )
}

function isSuccessfulWorkflowOutput(output: unknown): boolean {
  if (output && typeof output === 'object' && 'success' in output) {
    return output.success !== false
  }
  if (isExitReason(output)) {
    return output.type === 'Exit'
  }
  return true
}

function notifyUsageMeterCreated(callback: ((meter: UsageMeter) => void) | undefined, meter: UsageMeter, logger: Logger): void {
  try {
    callback?.(meter)
  } catch (error) {
    logger.warn(`Usage meter callback failed: ${errorMessage(error)}`)
  }
}

export function runWorkflow<TInput, TOutput, TTools extends ToolRegistry>(
  workflow: WorkflowFn<TInput & BaseWorkflowInput, TOutput, TTools>,
  workflowInput: TInput,
  options: RunWorkflowOptions & { errorResult: 'exitReason' },
): Promise<TOutput | ExitReason>
export function runWorkflow<TInput, TOutput, TTools extends ToolRegistry>(
  workflow: WorkflowFn<TInput & BaseWorkflowInput, TOutput, TTools>,
  workflowInput: TInput,
  options: RunWorkflowOptions & { errorResult: 'structured' },
): Promise<TOutput | StructuredWorkflowFailure>
export function runWorkflow<TInput, TOutput, TTools extends ToolRegistry>(
  workflow: WorkflowFn<TInput & BaseWorkflowInput, TOutput, TTools>,
  workflowInput: TInput,
  options: RunWorkflowOptions,
): Promise<TOutput | undefined>
export async function runWorkflow<TInput, TOutput, TTools extends ToolRegistry>(
  workflow: WorkflowFn<TInput & BaseWorkflowInput, TOutput, TTools>,
  workflowInput: TInput,
  options: RunWorkflowOptions,
): Promise<TOutput | ExitReason | StructuredWorkflowFailure | undefined> {
  const { commandName, context, logger, interactive, providerOverride } = options
  const emitProgress = createWorkflowProgressEmitter(options.onEvent, logger)
  let workflowFinished = false
  const finishWorkflow = async (success: boolean) => {
    if (workflowFinished) {
      return
    }
    workflowFinished = true
    await emitProgress({ kind: 'workflow-finished', success })
  }

  await emitProgress({ kind: 'workflow-started' })

  let parsedOptions: Awaited<ReturnType<typeof parseOptions>>
  try {
    parsedOptions = await parseOptions(context, { commandName })
  } catch (error) {
    await finishWorkflow(false)
    if (options.errorResult === 'exitReason') {
      return toTerminalExitReason(error)
    }
    if (options.errorResult === 'structured') {
      return toStructuredWorkflowFailure(error)
    }
    throw error
  }
  const { providerConfig, config, verbose, maxMessageCount, budget } = parsedOptions
  const yes = context.yes

  const additionalTools: BaseWorkflowInput['additionalTools'] = {}
  if (config.tools?.search) {
    additionalTools.search = search
  }

  // Initialize MCP manager if MCP servers are configured
  const mcpManager = new McpManager(logger)

  // Determine interactive mode: respect explicit values in input, then options, then default based on yes flag
  // Safely access interactive property with optional chaining in case workflowInput doesn't extend BaseWorkflowInput
  const resolvedInteractive = (workflowInput as BaseWorkflowInput | undefined)?.interactive ?? interactive ?? yes !== true
  const stateless = (workflowInput as { stateless?: boolean } | undefined)?.stateless === true

  const finalWorkflowInput: TInput & BaseWorkflowInput = {
    ...workflowInput,
    interactive: resolvedInteractive,
    additionalTools,
    config,
    onWorkflowProgress: emitProgress,
  }

  // Initialize pricing service (always enabled)
  const pricingService = new PricingService(merge({}, prices, config.prices ?? {}))

  const usage = new UsageMeter(merge({}, prices, config.prices ?? {}), {
    maxMessages: maxMessageCount,
    maxCost: budget,
    pricingService,
  })

  notifyUsageMeterCreated(options.onUsageMeterCreated, usage, logger)

  const printTaskEvent = printEvent(verbose, usage, process.stderr)
  const progressState: WorkflowProgressState = { modelOutputStarted: false }
  const taskEventCallback: TaskEventCallback = async (event) => {
    printTaskEvent(event)
    for (const progressEvent of workflowProgressEventsFromTaskEvent(event, progressState)) {
      await emitProgress(progressEvent)
    }
  }
  const finishWithError = async (error: unknown): Promise<ExitReason | StructuredWorkflowFailure> => {
    const exitReason = toTerminalExitReason(error)
    await taskEventCallback({ kind: TaskEventKind.EndTask, exitReason })
    await finishWorkflow(false)
    if (options.errorResult === 'exitReason') {
      return exitReason
    }
    if (options.errorResult === 'structured') {
      return toStructuredWorkflowFailure(error)
    }
    throw error
  }

  // Get command config once and reuse
  let commandConfig = providerConfig.getConfigForCommand(commandName)

  // Apply provider/model overrides if provided
  if (providerOverride) {
    const { provider: overrideProvider, model: overrideModel, parameters: overrideParameters } = providerOverride

    if (commandConfig) {
      // Create a merged config with overrides
      // Validate provider is a valid AiProvider enum value
      const validProvider =
        overrideProvider && Object.values(AiProvider).includes(overrideProvider as AiProvider)
          ? (overrideProvider as AiProvider)
          : commandConfig.provider

      // Warn if provider override was provided but invalid
      if (overrideProvider && validProvider !== overrideProvider) {
        logger.warn(
          `Invalid provider override: "${overrideProvider}". Valid providers: ${Object.values(AiProvider).join(', ')}. Falling back to configured provider.`,
        )
      }

      commandConfig = {
        ...commandConfig,
        provider: validProvider,
        model: overrideModel || commandConfig.model,
        parameters: overrideParameters ? { ...commandConfig.parameters, ...overrideParameters } : commandConfig.parameters,
      }
    } else if (overrideProvider) {
      // No base config, but overrides provided - create config from overrides
      // resolveModelConfig will handle validation
      commandConfig = providerConfig.resolveModelConfig({
        provider: overrideProvider,
        model: overrideModel,
        parameters: overrideParameters,
      })
    }
  }

  // All workflows currently require a provider, so validate config exists
  if (!commandConfig?.provider || !commandConfig.model) {
    const error = new ConfigurationError(
      `No provider configured for command: ${commandName}. Please run "polka init" to configure your AI provider.`,
    )
    logger.error(`Error: ${error.message}`)
    return finishWithError(error)
  }

  logger.info('Provider:', commandConfig.provider)
  logger.info('Model:', commandConfig.model)

  let model: ReturnType<typeof getModel>
  try {
    model = getModel(commandConfig)
  } catch (error) {
    return finishWithError(error)
  }

  const excludeFiles = [...(config.excludeFiles ?? [])]

  // Initialize SQLiteMemoryStore for persistent memory storage
  let memoryStore: { close(): void } | undefined
  let sqliteMemoryStore: SQLiteMemoryStore | undefined
  try {
    const globalConfigPath = getGlobalConfigPath()
    const globalConfig = (await loadConfigAtPath(globalConfigPath)) as { memory?: { enabled: boolean; type: string; path?: string } } | null
    // Use same default configuration from core for consistency
    const memoryConfig = globalConfig?.memory || DEFAULT_MEMORY_CONFIG

    if (!stateless && memoryConfig.enabled && memoryConfig.type === 'sqlite') {
      // Determine project scope using shared utility
      const cwd = process.cwd()
      const scope = detectProjectScope(cwd)

      // Resolve db path
      const dbPath = memoryConfig.path || DEFAULT_MEMORY_CONFIG.path
      const resolvedDbPath = resolveHomePath(dbPath)

      // Ensure database directory exists
      const dbDir = dirname(resolvedDbPath)
      await mkdir(dbDir, { recursive: true, mode: 0o700 })

      // Create SQLiteMemoryStore instance
      const sqliteStore = new SQLiteMemoryStore({ enabled: true, type: 'sqlite', path: dbPath }, scope)
      sqliteMemoryStore = sqliteStore

      // Wrap with MemoryManager for safety limits and consistent behavior
      const memoryManager = new MemoryManager(sqliteStore)
      memoryStore = memoryManager
    }
  } catch (error) {
    // If memory store initialization fails, log warning but continue with in-memory store
    logger.warn(`Failed to initialize persistent memory store: ${error instanceof Error ? error.message : String(error)}`)
  }

  try {
    const providerFactory =
      options.getProvider ??
      ((providerOptions: ProviderOptions) =>
        getProvider(sqliteMemoryStore ? { ...providerOptions, memoryStore: sqliteMemoryStore } : providerOptions))
    let toolProvider = providerFactory({
      excludeFiles,
      yes: context.yes,
      getModel: (tool) => {
        const toolConfig = config.tools?.[tool as keyof typeof config.tools]
        if (toolConfig === false) {
          return undefined
        }
        // Inherit from the main command config
        const baseConfig = commandConfig

        if (typeof toolConfig === 'object') {
          // Merge to allow partial overrides (e.g. just model)
          const mergedConfig = { ...baseConfig, ...toolConfig }
          const resolvedConfig = providerConfig.resolveModelConfig(mergedConfig)
          if (resolvedConfig) {
            return getModel(resolvedConfig)
          }
        }

        // Fallback for true or undefined
        return getModel(baseConfig)
      },
    })
    const allowedWritePaths = (workflowInput as { allowedWritePaths?: string[] }).allowedWritePaths
    if (allowedWritePaths && allowedWritePaths.length > 0) {
      toolProvider = await createWritePathGuardedProvider(toolProvider, allowedWritePaths, process.cwd(), emitProgress, logger)
    }

    const providerOptions = getProviderOptions({
      provider: commandConfig.provider,
      modelId: commandConfig.model,
      parameters: commandConfig.parameters,
    })

    // Initialize skill context for Agent Skills support
    const skillContext = await initializeSkillContext()

    const parameters: AgentContextParameters = {
      providerOptions,
      scripts: config.scripts,
      retryCount: config.retryCount,
      requestTimeoutSeconds: config.requestTimeoutSeconds,
      usageMeter: usage,
      skillContext,
      mcpManager,
    }

    let workflowContext: BaseWorkflowContext<TTools>

    // Create a tools proxy with dynamic dispatch.
    // Note: We cast to WorkflowTools<TTools> even though the actual return type is Promise<ToolResponse>.
    // This is safe because ToolResponse is a union of all TTools[K]['output'] types, so at runtime
    // the returned value is always compatible with the expected type for the called tool.
    const tools = new Proxy({} as WorkflowTools<TTools>, {
      get: (_target, prop) => {
        // Return undefined for non-string properties (symbols, etc.)
        // and standard properties like 'then', 'toJSON' to avoid interfering
        // with JavaScript operations like Promise.then or JSON.stringify
        if (typeof prop !== 'string' || prop === 'then' || prop === 'toJSON') {
          return undefined
        }
        // Return undefined for unknown tools to support existence checks
        // Only return a function for known tools (including local tools and MCP tools)
        if (!toolHandlers.has(prop) && !localToolNames.includes(prop)) {
          return undefined
        }
        return (async (input: unknown) => {
          logger.debug(`Running tool: ${prop}`)
          try {
            return await toolCall({ tool: prop as never, input: input as never }, {
              parameters,
              model,
              agentCallback: taskEventCallback,
              toolProvider,
              yes: context.yes,
              workflowContext: workflowContext,
            } as ToolCallContext)
          } catch (error) {
            if (error instanceof UserCancelledError || error instanceof ProviderError || error instanceof McpError) {
              throw error
            }
            throw new ToolExecutionError(prop, error)
          }
        }) as WorkflowTools<TTools>[keyof TTools]
      },
    })

    workflowContext = {
      step: makeStepFn(),
      logger,
      tools,
    }

    // Connect to MCP servers inside the try block to ensure cleanup
    if (config.mcpServers && Object.keys(config.mcpServers).length > 0) {
      await mcpManager.connectToServers(config.mcpServers)
      const mcpTools = mcpManager.getFullToolInfos()
      if (mcpTools.length > 0) {
        additionalTools.mcpTools = mcpTools
        logger.info(`Loaded ${mcpTools.length} MCP tools`)
      }
    }

    logger.info('Running workflow...')
    const output = await workflow(finalWorkflowInput, workflowContext)

    // Wait for any pending usage updates to complete
    await usage.waitForPending()

    const successful = isSuccessfulWorkflowOutput(output)
    logger.info(successful ? '\n\nWorkflow completed successfully.' : '\n\nWorkflow failed.')
    logger.info(usage.getUsageText())
    await finishWorkflow(successful)
    return output
  } catch (e) {
    const error = e as unknown
    const exitReason = toTerminalExitReason(error)

    // Handle different error types with appropriate messaging
    if (error instanceof UserCancelledError) {
      logger.warn('Workflow cancelled by user.')
    } else if (error instanceof UsageLimitExceededError) {
      logger.error(`\n❌ Error: ${error.message}`)
    } else if (error instanceof AuthenticationError) {
      logger.error(`\n❌ Authentication Error: ${error.message}`)
    } else if (error instanceof ModelAccessError) {
      logger.error(`\n❌ Model Access Error: ${error.message}`)
    } else if (error instanceof ProviderError) {
      // Handle all other provider errors
      logger.error(`\n❌ Provider Error: ${error.message}`)
    } else if (error instanceof McpError) {
      // Handle all MCP errors
      logger.error(`\n❌ MCP Error: ${error.message}`)
    } else if (error instanceof ToolExecutionError) {
      logger.error(`\n❌ Tool Error: ${error.message}`)
    } else {
      // Generic error handling
      const message = errorMessage(error)
      logger.error(`\n❌ Error: ${message}`)
    }
    await taskEventCallback({
      kind: TaskEventKind.EndTask,
      exitReason,
    })

    // Wait for any pending usage updates to complete
    await usage.waitForPending()

    logger.info(usage.getUsageText())
    await finishWorkflow(false)
    if (options.errorResult === 'exitReason') {
      return exitReason
    }
    return options.errorResult === 'structured' ? toStructuredWorkflowFailure(error) : undefined
  } finally {
    // Close memory store
    if (memoryStore) {
      try {
        await memoryStore.close()
      } catch (error) {
        logger.warn(`Failed to close memory store: ${error instanceof Error ? error.message : String(error)}`)
      }
    }
    // Disconnect MCP servers
    await mcpManager.disconnectAll()
    logGlobalToolCallStats(process.stderr, verbose)
  }
}
